+// ─── Tile Patterns ───────────────────────────────────────────────
+
+function drawTileStone(ctx: CanvasRenderingContext2D, x: number, y: number, size: number) {
+  // Base stone gray
+  ctx.fillStyle = '#7d7d7d';
+  ctx.fillRect(x, y, size, size);
+
+  // Mortar lines
+  ctx.strokeStyle = '#a0a0a0';
+  ctx.lineWidth = 1;
+  // Horizontal mortar lines
+  ctx.beginPath();
+  ctx.moveTo(x, y + size * 0.33);
+  ctx.lineTo(x + size, y + size * 0.33);
+  ctx.moveTo(x, y + size * 0.66);
+  ctx.lineTo(x + size, y + size * 0.66);
+  // Vertical mortar lines
+  ctx.moveTo(x + size * 0.25, y);
+  ctx.lineTo(x + size * 0.25, y + size);
+  ctx.moveTo(x + size * 0.5, y);
+  ctx.lineTo(x + size * 0.5, y + size);
+  ctx.moveTo(x + size * 0.75, y);
+  ctx.lineTo(x + size * 0.75, y + size);
+  ctx.stroke();
+
+  // Slight shading on stones
+  ctx.fillStyle = 'rgba(0,0,0,0.1)';
+  ctx.fillRect(x + 1, y + 1, size * 0.24, size * 0.32);
+  ctx.fillRect(x + size * 0.26, y + size * 0.34, size * 0.23, size * 0.31);
+  ctx.fillRect(x + size * 0.52, y + size * 0.67, size * 0.22, size * 0.3);
+}
+
+function drawTileWood(ctx: CanvasRenderingContext2D, x: number, y: number, size: number) {
+  // Base wood color
+  ctx.fillStyle = '#a9745b';
+  ctx.fillRect(x, y, size, size);
+
+  // Horizontal planks lines
+  ctx.strokeStyle = '#7f563f';
+  ctx.lineWidth = 2;
+  for (let i = 1; i < 4; i++) {
+    const yLine = y + (size / 4) * i - 1;
+    ctx.beginPath();
+    ctx.moveTo(x, yLine);
+    ctx.lineTo(x + size, yLine);
+    ctx.stroke();
+  }
+
+  // Wood grain (curved lines)
+  ctx.strokeStyle = '#6b4a38';
+  ctx.lineWidth = 1;
+  for (let i = 0; i < 3; i++) {
+    const baseY = y + (size / 4) * i + size / 8;
+    ctx.beginPath();
+    ctx.moveTo(x + 2, baseY);
+    ctx.bezierCurveTo(x + size * 0.3, baseY - 3, x + size * 0.6, baseY + 3, x + size - 2, baseY);
+    ctx.stroke();
+  }
+}
+
+function drawTileCarpet(ctx: CanvasRenderingContext2D, x: number, y: number, size: number) {
+  // Base carpet red
+  ctx.fillStyle = '#b22222';
+  ctx.fillRect(x, y, size, size);
+
+  // Border pattern: small darker squares on edges
+  const borderSize = 3;
+  ctx.fillStyle = '#7f0000';
+  // Top and bottom border squares
+  for (let i = 0; i < size; i += borderSize * 2) {
+    ctx.fillRect(x + i, y, borderSize, borderSize);
+    ctx.fillRect(x + i + borderSize, y + size - borderSize, borderSize, borderSize);
+  }
+  // Left and right border squares
+  for (let i = 0; i < size; i += borderSize * 2) {
+    ctx.fillRect(x, y + i, borderSize, borderSize);
+    ctx.fillRect(x + size - borderSize, y + i + borderSize, borderSize, borderSize);
+  }
+
+  // Subtle diagonal lines pattern
+  ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
+  ctx.lineWidth = 1;
+  for (let i = -size; i < size; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(x + i, y);
+    ctx.lineTo(x + i + size, y + size);
+    ctx.stroke();
+  }
+}
+
+function drawTileCobblestone(ctx: CanvasRenderingContext2D, x: number, y: number, size: number) {
+  // Base dirt color
+  ctx.fillStyle = '#6b5a4c';
+  ctx.fillRect(x, y, size, size);
+
+  // Draw irregular circles (cobblestones)
+  const stones = [
+    { cx: x + size * 0.3, cy: y + size * 0.35, r: size * 0.15 },
+    { cx: x + size * 0.7, cy: y + size * 0.3, r: size * 0.18 },
+    { cx: x + size * 0.5, cy: y + size * 0.7, r: size * 0.2 },
+    { cx: x + size * 0.2, cy: y + size * 0.7, r: size * 0.12 },
+  ];
+  ctx.fillStyle = '#8c7b6a';
+  stones.forEach(({ cx, cy, r }) => {
+    ctx.beginPath();
+    ctx.ellipse(cx, cy, r * 1.1, r * 0.9, Math.random() * Math.PI, 0, Math.PI * 2);
+    ctx.fill();
+    ctx.strokeStyle = '#5a4a3a';
+    ctx.lineWidth = 1;
+    ctx.stroke();
+  });
+}
+
+// ─── Draw tiled floor ─────────────────────────────────────────────
+
+function drawTiledFloor(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
+  const tileSize = 16;
+  // Map CharacterType to floor tile function
+  const floorTypeMap: Record<CharacterType, (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => void> = {
+    king: drawTileStone,
+    nobility: drawTileWood,
+    knight: drawTileCarpet,
+    squire: drawTileCobblestone,
+    healer: drawTileStone,
+    sentinel: drawTileWood,
+    scribe: drawTileCarpet,
+    judge: drawTileCobblestone,
+    blacksmith: drawTileStone,
+  };
+  const drawTile = floorTypeMap[type] ?? drawTileStone;
+
+  const cols = Math.ceil(w / tileSize);
+  const rows = Math.ceil(h / tileSize);
+  for (let row = 0; row < rows; row++) {
+    for (let col = 0; col < cols; col++) {
+      const tx = x + col * tileSize;
+      const ty = y + row * tileSize;
+      drawTile(ctx, tx, ty, tileSize);
+    }
+  }
 }

-// ─── Main character draw ───────────────────────────────────────────
