-// ─── Room rendering ────────────────────────────────────────────────
-
-export function drawRoom(
-  ctx: CanvasRenderingContext2D,
-  type: CharacterType,
-  x: number, y: number, w: number, h: number, frame: number,
-) {
-  const roomBg: Record<CharacterType, string> = {
-    king: '#1e0e2a', nobility: '#14203a', knight: '#142030', squire: '#142014',
-    healer: '#141830', sentinel: '#0e1424', scribe: '#201808', judge: '#14101a', blacksmith: '#181008',
-  };
-  ctx.fillStyle = roomBg[type];
-  ctx.fillRect(x, y, w, h);
-
-  const wallH = h * 0.38;
-  drawTiledWall(ctx, x, y, w, wallH, type);
-  drawTiledFloor(ctx, x, y + wallH, w, h - wallH, type);
-
-  // Wall-floor shadow
-  const grad = ctx.createLinearGradient(x, y + wallH, x, y + wallH + 8);
-  grad.addColorStop(0, 'rgba(0,0,0,0.35)'); grad.addColorStop(1, 'rgba(0,0,0,0)');
-  ctx.fillStyle = grad;
-  ctx.fillRect(x, y + wallH, w, 8);
-
-  drawRoomFurniture(ctx, type, x, y, w, h, frame);
-  drawRoomLighting(ctx, type, x, y, w, h);
-
-  const rid = `${type}-${x}`;
